class Solution {
    public int smallestValue(int n) {
        while (true) {
            int sum = 0, i = 2;
            while (i * i <= n) {
                if (n % i == 0) {
                    sum += i;
                    while (n % i == 0) n /= i;
                }
                i++;
            }
            if (n > 1) sum += n;
            if (sum == n) return n;
            n = sum;
        }
    }
}
